import{_ as a,o,c as d,a2 as t}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Configuração","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/configuration.md","filePath":"pt/guide/configuration.md"}'),s={name:"pt/guide/configuration.md"};function i(r,e,n,c,l,p){return o(),d("div",null,[...e[0]||(e[0]=[t(`<h1 id="configuracao" tabindex="-1">Configuração <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuração&quot;">​</a></h1><p>O Clearance vem com valores padrão sensatos, pelo que funciona imediatamente após a <a href="/clearance-docs/pt/guide/installation.html">instalação</a>. Publique o ficheiro de configuração quando precisar de personalizar o prefixo de rota, o middleware, os modelos contextuais, ou qualquer outra definição.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Isto publica <code>config/clearance.php</code>.</p><h2 id="referencia-de-configuracao" tabindex="-1">Referência de configuração <a class="header-anchor" href="#referencia-de-configuracao" aria-label="Permalink to &quot;Referência de configuração&quot;">​</a></h2><p>Esta é a referência definitiva para cada chave em <code>config/clearance.php</code>. As restantes páginas desta documentação remetem para aqui em vez de repetir a tabela.</p><table tabindex="0"><thead><tr><th>Chave</th><th>Padrão</th><th>Finalidade</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>Prefixo de URI para todas as rotas do painel.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Aplicado a todas as rotas do painel antes de <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Permissão verificada pelo middleware de acesso.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>Assume por padrão <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Interruptor principal do módulo de Utilizadores (rotas + componentes Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - modelos que podem atuar como contextos de vinculação de papéis.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Aplica a convenção de nomenclatura <code>group-action</code> para permissões.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Carácter separador - apenas <code>&#39;-&#39;</code> ou <code>&#39;_&#39;</code>.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Substitui os guards auto-detetados a partir de <code>config/auth.php</code>. Vazio = auto-detetar todos.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Drivers aceites ao injetar guards de base de dados em <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Layout Blade para componentes de página completa. <code>null</code> = padrão da aplicação hospedeira (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Atribui automaticamente o papel padrão configurado nas Configurações no evento <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Opcional: <code>super_admin</code> contorna todas as verificações de Gate em toda a aplicação.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = auto-deteta via <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="convencao-de-nomenclatura-de-permissoes" tabindex="-1">Convenção de nomenclatura de permissões <a class="header-anchor" href="#convencao-de-nomenclatura-de-permissoes" aria-label="Permalink to &quot;Convenção de nomenclatura de permissões&quot;">​</a></h2><p>As permissões devem seguir o formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Desative a imposição por ambiente com <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">O separador é validado no arranque</p><p>O valor de <code>naming_separator</code> é a única peça desta configuração que chega a um fragmento SQL bruto (agrupamento/ordenação de permissões), pelo que apenas <code>-</code> ou <code>_</code> são aceites.</p></div><h2 id="personalizar-o-middleware" tabindex="-1">Personalizar o middleware <a class="header-anchor" href="#personalizar-o-middleware" aria-label="Permalink to &quot;Personalizar o middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Os nomes de rota mantêm-se estáveis independentemente de alterações ao prefixo ou ao middleware - ver o <a href="/clearance-docs/pt/guide/quick-start.html">Início Rápido</a> para a tabela completa de rotas.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/guide/quick-start.html">Início Rápido</a> - montar o painel com estas definições aplicadas</li><li><a href="/clearance-docs/pt/guide/publishing.html">Publicação de recursos</a> - publicar traduções e compreender a chave <code>layout</code></li><li><a href="/clearance-docs/pt/features/guards.html">Guards</a> - como <code>guards</code> e <code>allowed_guard_drivers</code> são usados</li><li><a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> - como funciona <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const m=a(s,[["render",i]]);export{h as __pageData,m as default};
